import requests

def fetch_active_challenges():
    try:
        response = requests.get("https://api.topcoder.com/challenges/active")
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"Error fetching active challenges: {e}")
        return []

def solve(*args):
    active_challenges = fetch_active_challenges()
    return active_challenges
